        while True:
            if self.keys[index] is None or self.keys[index] is self.tombstone:
                self.keys[index] = key
                self.values[index] = value
                return
            elif self.keys[index] == key:
                self.values[index] = value
                return
            index = (index + 1) % self.capacity

